using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9: discriminator property renamed from "Discriminator" to "$type".
        // Preserve old name so existing documents remain readable.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // EF Core 9: id format changed from "Blog|1" to just "1".
        // Preserve old compound format so existing documents remain accessible.
        modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

        // EF Core 9: HasIndex now throws for Cosmos entities.
        // Removed — manage indexing via Azure Portal or Bicep instead.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

